"use strict";(self.webpackChunkdeep_notes=self.webpackChunkdeep_notes||[]).push([[87122],{676620:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>r,default:()=>u,frontMatter:()=>a,metadata:()=>o,toc:()=>l});const o=JSON.parse('{"id":"technologies/confluent/confluent-cloud-networking/22-authorizing-using-rbac-and-acls","title":"Authorizing Using RBAC and ACLs","description":"Your identities will need access to Confluent Cloud, whether it is to create applications or send and receive data. Allowing them to access your cluster as easily as possible is important to how well your business runs. At the same time, your access model needs to be structured in a way where you can easily add, remove, change, and verify permissions.","source":"@site/docs/technologies/confluent/confluent-cloud-networking/22-authorizing-using-rbac-and-acls.md","sourceDirName":"technologies/confluent/confluent-cloud-networking","slug":"/technologies/confluent/confluent-cloud-networking/22-authorizing-using-rbac-and-acls","permalink":"/technologies/confluent/confluent-cloud-networking/22-authorizing-using-rbac-and-acls","draft":false,"unlisted":false,"editUrl":"https://github.com/deepaksood619/deepaksood619.github.io/tree/master/docs/technologies/confluent/confluent-cloud-networking/22-authorizing-using-rbac-and-acls.md","tags":[],"version":"current","lastUpdatedBy":"Deeapak Sood","lastUpdatedAt":1765348619000,"frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Authenticating Users and Applications","permalink":"/technologies/confluent/confluent-cloud-networking/21-authenticating-users-and-applications"},"next":{"title":"Understanding Encryption","permalink":"/technologies/confluent/confluent-cloud-networking/23-understanding-encryption"}}');var s=t(474848),i=t(28453);const a={},r="Authorizing Using RBAC and ACLs",c={},l=[{value:"ACLs",id:"acls",level:2},{value:"RBACs",id:"rbacs",level:2},{value:"RBAC roles",id:"rbac-roles",level:2},{value:"RBAC Considerations",id:"rbac-considerations",level:2},{value:"ACLs and RBAC Order of Precedence",id:"acls-and-rbac-order-of-precedence",level:2}];function d(e){const n={a:"a",h1:"h1",h2:"h2",header:"header",img:"img",li:"li",p:"p",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"authorizing-using-rbac-and-acls",children:"Authorizing Using RBAC and ACLs"})}),"\n",(0,s.jsx)(n.p,{children:"Your identities will need access to Confluent Cloud, whether it is to create applications or send and receive data. Allowing them to access your cluster as easily as possible is important to how well your business runs. At the same time, your access model needs to be structured in a way where you can easily add, remove, change, and verify permissions."}),"\n",(0,s.jsx)(n.p,{children:"Authorization is where you will make sure that your authenticated users have the access they should have, and no more or no less. It is not unheard of to have to authorize hundreds, thousands, or even tens of thousands of identities. If you\u2019ve ever used the open source implementation of Kafka, you may be familiar with the burdensome process of having to create an LDAP store to configure your group, role, and user hierarchies, then applying ACL based on the group and role hierarchies, and finally implementing a custom authorizer that pairs the groups and users in LDAP with those in Kafka."}),"\n",(0,s.jsx)(n.p,{children:"None of that extra effort is necessary with Confluent Cloud. Instead, there are two methods for authorizing your identities: access control lists (ACLs), and role-based access control (RBAC)."}),"\n",(0,s.jsx)(n.h2,{id:"acls",children:"ACLs"}),"\n",(0,s.jsx)(n.p,{children:"ACLs are tables that store identities and what they can do or see (the resources they can access and permissions they have) within Confluent Cloud. The important thing to remember is that permissions are tied to each identity and linked to the access they have been given for each resource. If an identity changes teams or scope, you will have to make sure to address things at an individual level. If at any point even one of these changes is missed, or configured incorrectly, you now have identities that have access to more than what they should."}),"\n",(0,s.jsx)(n.p,{children:"This problem is only made worse as the number of identities in your organization increases. Verifying permissions for compliance with laws and regulations can become quite a labor-intensive and time-consuming process, not to mention a potential security risk."}),"\n",(0,s.jsx)(n.p,{children:"ACLs are specific to Kafka resources and don\u2019t extend to other Confluent Cloud concepts, such as environments and organizations. Managing ACLs for a small number of identities likely isn\u2019t a big deal. However, if you are working with a large organization with hundreds or thousands of identities, using ACLs doesn\u2019t scale. You\u2019re left with the second option for organizing identities, role-based access control."}),"\n",(0,s.jsx)(n.h2,{id:"rbacs",children:"RBACs"}),"\n",(0,s.jsx)(n.p,{children:"RBACs allow you to configure predefined roles within your organization. Identities are assigned to a role and gain access to an organization, environment, cluster, or specific Kafka resources like topics, consumer groups, and transactional IDs based on that role."}),"\n",(0,s.jsx)(n.p,{children:"For example, imagine a user, Milton, who is part of a group of users that require access to read data from your Purchases topic. Using ACLs, Milton\u2019s identity is granted permission to access the read data. If tomorrow Milton also requires access to the read data from a topic called Returns, that permission must be added to Milton\u2019s user identity (and the identity of everyone else who also now needs access)."}),"\n",(0,s.jsx)(n.p,{children:"Using RBACs, Milton is assigned to the DeveloperRead role. Each identity assigned to the DeveloperRead role has access to read data from the Purchase topic. Adding access to the Returns topic can be achieved by changing the DeveloperRead role scope to now include access to the Returns topic. Every identity within that role gains the correct access. As opposed to ACLs, RBAC integrates with a centralized identity management system and allows much simpler scaling for large organizations. From a compliance perspective, it\u2019s safer and simpler to verify your RBAC roles to prove compliance than to attempt to confirm each individual ACL identity."}),"\n",(0,s.jsx)(n.h2,{id:"rbac-roles",children:"RBAC roles"}),"\n",(0,s.jsxs)(n.p,{children:["Confluent Cloud has the following roles preconfigured. You may want to keep a copy of this table to reference as you begin to plan your access architecture. You may want to\xa0",(0,s.jsx)(n.a,{href:"https://docs.confluent.io/cloud/current/access-management/access-control/cloud-rbac.html#ccloud-rbac-roles",children:"reference the documentation"}),"\xa0for more in-depth details on each of these roles."]}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.img,{src:"https://images.ctfassets.net/gt6dp23g0g38/la7jRx1RlQaz6tSBlp9dm/c78c4ef3ef330761e47c7bdc0d4458bb/rbac-roles.jpg",alt:"rbac-roles"})}),"\n",(0,s.jsx)(n.p,{children:"Also, there are a couple of things to keep in mind as you use RBAC in Confluent Cloud:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"RBAC for Kafka is available only on Standard and Dedicated clusters. To create service accounts, you must be granted the OrganizationAdmin role. All the other cluster administration roles (EnvironmentAdmin, CloudClusterAdmin, and ResourceOwner) can grant or revoke permissions for existing service accounts on the resources that they control."}),"\n",(0,s.jsx)(n.li,{children:"Role bindings are limited like every other resource on Confluent Cloud. You will want to check the official documentation to see the current guidance."}),"\n",(0,s.jsx)(n.li,{children:"You must use version 2.8.1 or later of the Confluent CLI to manage RBAC roles."}),"\n"]}),"\n",(0,s.jsx)(n.h2,{id:"rbac-considerations",children:"RBAC Considerations"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"If you use OAuth for authentication you will be creating identity pools for your principals. There are two parts to every identity pool: who can use the pool, and what the pool can access. The \u201cwho\u201d is a set of conditions that the identity needs to satisfy in order to use the pool. The \u201cwhat\u201d is defined by ACLs and RBAC roles."}),"\n",(0,s.jsx)(n.li,{children:"You can use a mix of ACLs and RBACs. This may be helpful if you need to provide a small set of identities with access to a resource in your Confluent Cloud cluster. However, as an investment in the future, we recommend going with RBACs over ACLs."}),"\n"]}),"\n",(0,s.jsx)(n.h2,{id:"acls-and-rbac-order-of-precedence",children:"ACLs and RBAC Order of Precedence"}),"\n",(0,s.jsx)(n.p,{children:"As both ACLs and RBAC provide authorization, there is an order of precedence in granting access:"}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.img,{src:"https://images.ctfassets.net/gt6dp23g0g38/rIAdqJXoWfIPbntYRSKkw/d6331054ece90e40cb38e92cb578f962/granting-authorization.jpg",alt:"granting-authorization"})})]})}function u(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},28453:(e,n,t)=>{t.d(n,{R:()=>a,x:()=>r});var o=t(296540);const s={},i=o.createContext(s);function a(e){const n=o.useContext(i);return o.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),o.createElement(i.Provider,{value:n},e.children)}}}]);